import sys
import itertools

def is_valid_sequence(seq):
    for i in range(len(seq) - 1):
        a = seq[i]
        b = seq[i + 1]
        diff = 0
        for j in range(len(a)):
            if a[j] != b[j]:
                diff += 1
                if diff > 1:
                    break
        if diff != 1:
            return False
    return True

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    M = int(input[1])
    strings = input[2:2 + N]

    for perm in itertools.permutations(strings):
        if is_valid_sequence(perm):
            print("Yes")
            return
    print("No")

if __name__ == "__main__":
    main()
